import { Component, OnInit } from '@angular/core';
import { RouterLink } from '@angular/router';
import { MenuItem } from 'primeng/api';
import { Menubar } from 'primeng/menubar';
import { MenubarModule } from 'primeng/menubar'; // במקום 'primeng/api' או ייבוא פשוט
import { A } from '../../Services/AutorService';

@Component({
  selector: 'app-header-comp',
  imports: [MenubarModule, RouterLink],
  templateUrl: './header-comp.html',
  styleUrl: './header-comp.scss',
})
export class HeaderComp implements OnInit {
    items: MenuItem[] | undefined;
    constructor(private authComp: AuthComp) { }

    ngOnInit() {
        this.items = [
            {
                label: 'Home',
                icon: 'pi pi-home',
                routerLink: '/'
            },
            {
                label: 'Features',
                icon: 'pi pi-star',
                routerLink: '/addWorker'
            },
            
             {
                label: 'AllGifts',
                icon: 'pi pi-gift',
                routerLink: '/all-gifts'
            },
             {
                label: 'My Cart',
                icon: 'pi pi-home',
                routerLink: '/cart'
            },
            {
                label: 'Projects',
                icon: 'pi pi-search',
                items: [
                    {
                        label: 'Components',
                        icon: 'pi pi-bolt'
                    },
                    {
                        label: 'Blocks',
                        icon: 'pi pi-server'
                    },
                    {
                        label: 'UI Kit',
                        icon: 'pi pi-pencil'
                    },
                    {
                        label: 'Templates',
                        icon: 'pi pi-palette',
                        items: [
                            {
                                label: 'Apollo',
                                icon: 'pi pi-palette'
                            },
                            {
                                label: 'Ultima',
                                icon: 'pi pi-palette'
                            }
                        ]
                    }
                ]
            },
            {
                label: 'User',
                icon: 'pi pi-user',
                routerLink: '/user'
            }
        ]
        if (this.authComp.isManager()) {
      this.items.push({
        label: 'All Donors',
        icon: 'pi pi-users',
        routerLink: '/admin-donors'
      });
    }
}
